module alu(
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);

    // Internal signals
    wire [31:0] result;
    wire [31:0] add_result;
    wire [31:0] sub_result;
    wire [31:0] and_result;
    wire [31:0] or_result;
    wire [31:0] xor_result;
    wire [31:0] sl_result;
    wire [31:0] sr_result;
    wire [31:0] sra_result;
    wire [31:0] lui_result;
    wire [31:0] adder_result;
    wire [31:0] subtractor_result;
    wire adder_carry;
    wire subtractor_carry;
    wire overflow_flag;
    wire carry_flag;
    wire zero_flag;
    wire negative_flag;
    wire shift_carry;
    wire shift_overflow;

    // Arithmetic and logic units
    assign and_result = a & b;
    assign or_result = a | b;
    assign xor_result = a ^ b;
    assign and_result = a & b;
    assign or_result = a | b;
    assign xor_result = a ^ b;
    assign sl_result = a << b[4:0];
    assign sr_result = a >> b[4:0];
    assign sra_result = a >>> b[4:0];
    assign lui_result = {b[15:0], 16'b0};

    // Adder
    assign {adder_carry, adder_result} = a + b;
    assign overflow_flag = (a[31] == b[31]) && (adder_result[31] != a[31]);
    assign carry_flag = adder_carry;
    assign zero_flag = (adder_result == 32'b0);
    assign negative_flag = adder_result[31];

    // Subtractor
    assign {subtractor_carry, subtractor_result} = a - b;
    assign shift_carry = (b[4:0] == 5'b0) ? 1'b0 : sr_result[31];
    assign shift_overflow = (b[4:0] == 5'b0) ? 1'b0 : (a[31] ^ subtractor_result[31]);

    // Output multiplexer
    assign result = (aluc == 6'b000000) ? adder_result :
                    (aluc == 6'b000001) ? subtractor_result :
                    (aluc == 6'b000010) ? and_result :
                    (aluc == 6'b000011) ? or_result :
                    (aluc == 6'b000100) ? xor_result :
                    (aluc == 6'b000101) ? sl_result :
                    (aluc == 6'b000110) ? sr_result :
                    (aluc == 6'b000111) ? sra_result :
                    (aluc == 6'b001000) ? lui_result :
                    32'b0;

    // Output signals
    assign r = result;
    assign zero = zero_flag;
    assign carry = carry_flag;
    assign negative = negative_flag;
    assign overflow = overflow_flag;
    assign flag = overflow ^ carry;

endmodule
